import React, { useState, useEffect } from 'react';
import api from '../services/api';
import SeleccionarTipoOferta from './SeleccionarTipoOferta';

const CrearOferta = () => {
  const [modo, setModo] = useState(null); // 'regular' o 'campesena' o null
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [mostrarFormularioEmpresa, setMostrarFormularioEmpresa] = useState(false);
  const [instructoresVisibles, setInstructoresVisibles] = useState({
    primerInstructor: '',
    segundoInstructor: ''
  });

  // Estados para las opciones de los selects
  const [programas, setProgramas] = useState([]);
  const [modalidades, setModalidades] = useState([]);
  const [tiposPrograma, setTiposPrograma] = useState([]);
  const [tiposOferta, setTiposOferta] = useState([]);
  const [municipios, setMunicipios] = useState([]);
  const [programasEspeciales, setProgramasEspeciales] = useState([]);
  const [empresas, setEmpresas] = useState([]);

  // Estado del formulario base (común para ambos modos)
  const [formData, setFormData] = useState({
    programa_formacion: '',
    modalidad: '',
    tipo_programa: '',
    tipo_oferta: '',
    cupo_maximo: '',
    ambiente: {
      nombre: ''
    },
    fechas: {
      inicio: '',
      fin: ''
    },
    ubicacion: {
      departamento: 'Cauca',
      municipio: '',
      direccion: ''
    },
    empresa_solicitante: '',
    subsector_economico: {
      nombre: ''
    },
    programa_especial: '',
    convenio: {
      nombre: ''
    },
    horario: {
      hora_inicio: '08:00',
      hora_fin: '12:00',
      dias: []
    },
    firma_digital_pdf: null,
    carta_pdf: null
  });

  // Estado específico para modo Campesena
  const [campesenaData, setCampesenaData] = useState({
    duracion_meses: '',
    instructores: [
      {
        tipo: '',
        nombre: '',
        correo: '',
        celular: '',
        fechas: ['', '', '', '', '']
      },
      {
        tipo: '',
        nombre: '',
        correo: '',
        celular: '',
        fechas: ['', '', '', '', '']
      }
    ]
  });

  // Estado para crear una nueva empresa
  const [nuevaEmpresa, setNuevaEmpresa] = useState({
    nombre: '',
    nit: '',
    fecha_creacion: '',
    tipo_empresa: 'Privada',
    direccion: '',
    representante_legal: {
      nombre_completo: '',
      documento_identidad: '',
      telefono: '',
      correo: ''
    },
    contacto: {
      nombre_completo: '',
      cargo: '',
      telefono: '',
      correo: ''
    },
    numero_empleados: ''
  });

  // ===== Cargar datos al montar el componente =====
  useEffect(() => {
    cargarDatosIniciales();
  }, []);

  const cargarDatosIniciales = async () => {
    try {
      console.log('🔄 Cargando datos iniciales...');
      
      const [
        programasRes,
        modalidadesRes,
        tiposProgramaRes,
        tiposOfertaRes,
        municipiosRes,
        programasEspecialesRes,
        empresasRes
      ] = await Promise.all([
        api.get('/programas-formacion'),
        api.get('/modalidades'),
        api.get('/tipos-programa'),
        api.get('/tipos-oferta'),
        api.get('/municipios'),
        api.get('/programas-especiales'),
        api.get('/empresas')
      ]);

      setProgramas(programasRes.data.data || []);
      setModalidades(modalidadesRes.data.data || []);
      setTiposPrograma(tiposProgramaRes.data.data || []);
      setTiposOferta(tiposOfertaRes.data.data || []);
      setMunicipios(municipiosRes.data.data || []);
      setProgramasEspeciales(programasEspecialesRes.data.data || []);
      setEmpresas(empresasRes.data.data || []);
      
      console.log('✅ Datos cargados correctamente');
    } catch (error) {
      console.error('❌ Error cargando datos:', error);
      setError('Error al cargar datos necesarios para el formulario');
    }
  };

  // ===== Lógica para determinar instructores según tipo de programa (solo Campesena) =====
  const determinarInstructores = (tipoProgramaId) => {
    const tipoSeleccionado = tiposPrograma.find(t => t._id === tipoProgramaId);
    if (!tipoSeleccionado) return { primero: '', segundo: '' };

    const tipoNombre = tipoSeleccionado.nombre;
    
    const instructores = {
      'Técnico': { primero: 'Empresarial', segundo: 'Popular' },
      'Empresarial': { primero: 'Técnico', segundo: 'Popular' },
      'Popular': { primero: 'Técnico', segundo: 'Empresarial' }
    };
    
    return instructores[tipoNombre] || { primero: '', segundo: '' };
  };

  // ===== Efecto para actualizar instructores cuando cambia tipo_programa (solo Campesena) =====
  useEffect(() => {
    if (modo === 'campesena' && formData.tipo_programa) {
      const instructores = determinarInstructores(formData.tipo_programa);
      setInstructoresVisibles(instructores);
      
      setCampesenaData(prev => ({
        ...prev,
        instructores: [
          { ...prev.instructores[0], tipo: instructores.primero },
          { ...prev.instructores[1], tipo: instructores.segundo }
        ]
      }));
    }
  }, [formData.tipo_programa, tiposPrograma, modo]);

  // ===== Función para manejar archivos PDF =====
  const handleFileChange = (e) => {
    const { name, files } = e.target;
    if (files && files[0]) {
      if (files[0].type !== 'application/pdf') {
        setError('Solo se permiten archivos PDF');
        return;
      }
      if (files[0].size > 5 * 1024 * 1024) {
        setError('El archivo no puede superar los 5MB');
        return;
      }
      setFormData({
        ...formData,
        [name]: files[0]
      });
    }
  };

  // ===== Función para cambios en campos normales =====
  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    
    if (type === 'checkbox') {
      if (name === 'horario.dias') {
        const dias = formData.horario.dias.includes(value)
          ? formData.horario.dias.filter(d => d !== value)
          : [...formData.horario.dias, value];
        setFormData({
          ...formData,
          horario: {
            ...formData.horario,
            dias
          }
        });
      }
    } else if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({
        ...formData,
        [parent]: {
          ...formData[parent],
          [child]: value
        }
      });
    } else {
      setFormData({
        ...formData,
        [name]: value
      });
    }
  };

  // ===== Función para cambios en instructores de Campesena =====
  const handleInstructorChange = (e, index) => {
    const { name, value } = e.target;
    const nuevosInstructores = [...campesenaData.instructores];
    
    if (name.includes('fechas')) {
      const fechaIndex = parseInt(name.split('[')[2].split(']')[0]);
      nuevosInstructores[index].fechas[fechaIndex] = value;
    } else {
      nuevosInstructores[index][name] = value;
    }
    
    setCampesenaData({ ...campesenaData, instructores: nuevosInstructores });
  };

  // ===== Función para cambios en datos específicos de Campesena =====
  const handleCampesenaChange = (e) => {
    const { name, value } = e.target;
    setCampesenaData({
      ...campesenaData,
      [name]: value
    });
  };

  // ===== Funciones para manejar la nueva empresa =====
  const handleNuevaEmpresaChange = (e) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setNuevaEmpresa({
        ...nuevaEmpresa,
        [parent]: {
          ...nuevaEmpresa[parent],
          [child]: value
        }
      });
    } else {
      setNuevaEmpresa({
        ...nuevaEmpresa,
        [name]: value
      });
    }
  };

  const crearNuevaEmpresa = async () => {
    try {
      setLoading(true);
      
      if (!nuevaEmpresa.nombre) throw new Error('El nombre de la empresa es obligatorio');
      if (!nuevaEmpresa.nit) throw new Error('El NIT es obligatorio');
      if (!nuevaEmpresa.fecha_creacion) throw new Error('La fecha de creación es obligatoria');
      if (!nuevaEmpresa.direccion) throw new Error('La dirección es obligatoria');
      if (!nuevaEmpresa.representante_legal.nombre_completo) throw new Error('El nombre del representante legal es obligatorio');
      if (!nuevaEmpresa.contacto.nombre_completo) throw new Error('El nombre del contacto es obligatorio');
      if (!nuevaEmpresa.contacto.telefono) throw new Error('El teléfono del contacto es obligatorio');
      if (!nuevaEmpresa.contacto.correo) throw new Error('El correo del contacto es obligatorio');
      if (!nuevaEmpresa.numero_empleados) throw new Error('El número de empleados es obligatorio');

      const response = await api.post('/empresas', nuevaEmpresa);
      
      setEmpresas([...empresas, response.data.data]);
      setFormData({ ...formData, empresa_solicitante: response.data.data._id });
      setMostrarFormularioEmpresa(false);
      
      setNuevaEmpresa({
        nombre: '',
        nit: '',
        fecha_creacion: '',
        tipo_empresa: 'Privada',
        direccion: '',
        representante_legal: {
          nombre_completo: '',
          documento_identidad: '',
          telefono: '',
          correo: ''
        },
        contacto: {
          nombre_completo: '',
          cargo: '',
          telefono: '',
          correo: ''
        },
        numero_empleados: ''
      });

    } catch (error) {
      console.error('Error creando empresa:', error);
      if (error.response?.data?.message) {
        setError(error.response.data.message);
      } else {
        setError(error.message);
      }
    } finally {
      setLoading(false);
    }
  };


  console.log('📤 Datos a enviar:', {
  formData,
  campesenaData,
  modo
});

// Verificar campos requeridos
console.log('Campos requeridos:', {
  programa_formacion: formData.programa_formacion,
  modalidad: formData.modalidad,
  tipo_programa: formData.tipo_programa,
  cupo_maximo: formData.cupo_maximo,
  empresa_solicitante: formData.empresa_solicitante
});


  // ===== Función para enviar el formulario =====
  const handleSubmit = async (e) => {
  e.preventDefault();
  setLoading(true);
  setError('');
  setSuccess('');

  try {
    // Validaciones básicas
    if (!formData.programa_formacion) throw new Error('Seleccione un programa');
    if (!formData.modalidad) throw new Error('Seleccione una modalidad');
    if (!formData.tipo_programa) throw new Error('Seleccione tipo de programa');
    if (!formData.tipo_oferta) throw new Error('Seleccione tipo de oferta');
    if (!formData.cupo_maximo) throw new Error('Ingrese cupo máximo');
    if (!formData.ambiente?.nombre) throw new Error('Ingrese nombre del ambiente');
    if (!formData.fechas?.inicio || !formData.fechas?.fin) throw new Error('Ingrese fechas');
    if (!formData.ubicacion?.municipio) throw new Error('Seleccione municipio');
    if (!formData.ubicacion?.direccion) throw new Error('Ingrese dirección');
    if (!formData.empresa_solicitante) throw new Error('Seleccione empresa');
    if (!formData.subsector_economico?.nombre) throw new Error('Ingrese subsector económico');
    if (!formData.convenio?.nombre) throw new Error('Ingrese nombre del convenio');
    if (formData.horario?.dias?.length === 0) throw new Error('Seleccione al menos un día');

    // Validar fechas
    const fechaInicio = new Date(formData.fechas.inicio);
    const fechaFin = new Date(formData.fechas.fin);
    if (fechaFin <= fechaInicio) {
      throw new Error('La fecha de fin debe ser posterior a la fecha de inicio');
    }

    // Validaciones específicas para Campesena
    if (modo === 'campesena') {
      if (!campesenaData.duracion_meses) throw new Error('Ingrese duración en meses');
      if (parseInt(campesenaData.duracion_meses) > 5) {
        throw new Error('Para programas Campesena, la duración máxima es 5 meses');
      }
      
      campesenaData.instructores.forEach((instructor, idx) => {
        if (!instructor.nombre) throw new Error(`Nombre del instructor ${idx + 1} es obligatorio`);
        if (!instructor.correo) throw new Error(`Correo del instructor ${idx + 1} es obligatorio`);
        if (!instructor.celular) throw new Error(`Celular del instructor ${idx + 1} es obligatorio`);
        instructor.fechas.forEach((fecha, fIdx) => {
          if (!fecha) throw new Error(`Fecha mes ${fIdx + 1} del instructor ${idx + 1} es obligatoria`);
        });
      });
    }

    // Después de crear formDataToSend y antes de api.post, agrega:

console.log('=== VERIFICACIÓN DE CAMPOS ===');
console.log('ambiente.nombre:', formData.ambiente?.nombre);
console.log('fechas.inicio:', formData.fechas?.inicio);
console.log('fechas.fin:', formData.fechas?.fin);
console.log('ubicacion.municipio:', formData.ubicacion?.municipio);
console.log('ubicacion.direccion:', formData.ubicacion?.direccion);
console.log('subsector_economico.nombre:', formData.subsector_economico?.nombre);
console.log('convenio.nombre:', formData.convenio?.nombre);
console.log('horario.hora_inicio:', formData.horario?.hora_inicio);
console.log('horario.hora_fin:', formData.horario?.hora_fin);
console.log('horario.dias:', formData.horario?.dias);

console.log('=== CONTENIDO DE FormData ===');
for (let pair of formDataToSend.entries()) {
  console.log(pair[0] + ':', pair[1]);
}

    // ===== CREAR FormData =====
const formDataToSend = new FormData();

  // Agregar campos simples
  formDataToSend.append('programa_formacion', formData.programa_formacion);
  formDataToSend.append('modalidad', formData.modalidad);
  formDataToSend.append('tipo_programa', formData.tipo_programa);
  formDataToSend.append('tipo_oferta', formData.tipo_oferta);
  formDataToSend.append('cupo_maximo', formData.cupo_maximo);
  formDataToSend.append('empresa_solicitante', formData.empresa_solicitante);
  formDataToSend.append('programa_especial', formData.programa_especial || '');

  // ===== VERIFICAR Y AGREGAR CAMPOS ANIDADOS =====
  // Ambiente
  if (!formData.ambiente?.nombre) throw new Error('El nombre del ambiente es obligatorio');
  formDataToSend.append('ambiente[nombre]', formData.ambiente.nombre);

  // Fechas
  if (!formData.fechas?.inicio) throw new Error('La fecha de inicio es obligatoria');
  if (!formData.fechas?.fin) throw new Error('La fecha de fin es obligatoria');
  formDataToSend.append('fechas[inicio]', formData.fechas.inicio);
  formDataToSend.append('fechas[fin]', formData.fechas.fin);

  // Ubicación
  if (!formData.ubicacion?.municipio) throw new Error('El municipio es obligatorio');
  if (!formData.ubicacion?.direccion) throw new Error('La dirección es obligatoria');
  formDataToSend.append('ubicacion[departamento]', formData.ubicacion.departamento);
  formDataToSend.append('ubicacion[municipio]', formData.ubicacion.municipio);
  formDataToSend.append('ubicacion[direccion]', formData.ubicacion.direccion);

  // Subsector económico
  if (!formData.subsector_economico?.nombre) throw new Error('El subsector económico es obligatorio');
  formDataToSend.append('subsector_economico[nombre]', formData.subsector_economico.nombre);

  // Convenio
  if (!formData.convenio?.nombre) throw new Error('El nombre del convenio es obligatorio');
  formDataToSend.append('convenio[nombre]', formData.convenio.nombre);

  // Horario
  if (!formData.horario?.hora_inicio) throw new Error('La hora de inicio es obligatoria');
  if (!formData.horario?.hora_fin) throw new Error('La hora de fin es obligatoria');
  formDataToSend.append('horario[hora_inicio]', formData.horario.hora_inicio);
  formDataToSend.append('horario[hora_fin]', formData.horario.hora_fin);

  // Días del horario (como array)
  if (formData.horario.dias.length === 0) throw new Error('Seleccione al menos un día');
  formData.horario.dias.forEach((dia, index) => {
    formDataToSend.append(`horario[dias][${index}]`, dia);
  });

  // Duración (siempre enviar)
  if (modo === 'campesena') {
    if (!campesenaData.duracion_meses) throw new Error('Ingrese duración en meses');
    formDataToSend.append('duracion_meses', campesenaData.duracion_meses);
  } else {
    formDataToSend.append('duracion_meses', '12');
  }

  // Instructores solo para Campesena
  if (modo === 'campesena') {
    // Validar instructores
    campesenaData.instructores.forEach((instructor, idx) => {
      if (!instructor.nombre) throw new Error(`Nombre del instructor ${idx + 1} es obligatorio`);
      if (!instructor.correo) throw new Error(`Correo del instructor ${idx + 1} es obligatorio`);
      if (!instructor.celular) throw new Error(`Celular del instructor ${idx + 1} es obligatorio`);
      instructor.fechas.forEach((fecha, fIdx) => {
        if (!fecha) throw new Error(`Fecha mes ${fIdx + 1} del instructor ${idx + 1} es obligatoria`);
      });
    });
    formDataToSend.append('instructores_campesena', JSON.stringify(campesenaData.instructores));
  }

  // Archivos PDF (opcionales)
  if (formData.firma_digital_pdf) {
    formDataToSend.append('firma_digital_pdf', formData.firma_digital_pdf);
  }
  if (formData.carta_pdf) {
    formDataToSend.append('carta_pdf', formData.carta_pdf);
  }

  console.log('📤 Enviando FormData...');

  // ===== ENVIAR COMO FormData =====
  const response = await api.post('/ofertas', formDataToSend, {
    headers: {
      'Content-Type': 'multipart/form-data'
    }
  });


    setSuccess('✅ Oferta creada exitosamente');
    console.log('✅ Respuesta:', response.data);

    // Resetear formulario después de 2 segundos
    setTimeout(() => {
      setModo(null);
      setFormData({
        programa_formacion: '',
        modalidad: '',
        tipo_programa: '',
        tipo_oferta: '',
        cupo_maximo: '',
        ambiente: { nombre: '' },
        fechas: { inicio: '', fin: '' },
        ubicacion: { departamento: 'Cauca', municipio: '', direccion: '' },
        empresa_solicitante: '',
        subsector_economico: { nombre: '' },
        programa_especial: '',
        convenio: { nombre: '' },
        horario: { hora_inicio: '08:00', hora_fin: '12:00', dias: [] },
        firma_digital_pdf: null,
        carta_pdf: null
      });
      setCampesenaData({
        duracion_meses: '',
        instructores: [
          { tipo: '', nombre: '', correo: '', celular: '', fechas: ['', '', '', '', ''] },
          { tipo: '', nombre: '', correo: '', celular: '', fechas: ['', '', '', '', ''] }
        ]
      });
    }, 2000);

  } catch (error) {
    console.error('❌ Error:', error);
    if (error.response?.data?.errors) {
      setError(error.response.data.errors.join(', '));
    } else if (error.response?.data?.message) {
      setError(error.response.data.message);
    } else {
      setError(error.message);
    }
  } finally {
    setLoading(false);
  }
};



  const diasSemana = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

  // Si no hay modo seleccionado, mostrar la pantalla de selección
  if (!modo) {
    return <SeleccionarTipoOferta onSeleccionar={setModo} />;
  }

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2 style={styles.title}>
          {modo === 'regular' ? '🟢 Crear Oferta Regular' : '🟠 Crear Oferta Campesena'}
        </h2>
        <button 
          onClick={() => setModo(null)}
          style={styles.cambiarModoButton}
        >
          ← Cambiar tipo de oferta
        </button>
      </div>
      
      {error && <div style={styles.errorAlert}>❌ {error}</div>}
      {success && <div style={styles.successAlert}>✅ {success}</div>}

      <form onSubmit={handleSubmit} style={styles.form}>
        
        {/* PROGRAMA DE FORMACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa de Formación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Programa:</label>
            <select 
              name="programa_formacion"
              value={formData.programa_formacion}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {programas.map(prog => (
                <option key={prog._id} value={prog._id}>
                  {prog.nombre_programa} - {prog.codigo}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Modalidad:</label>
            <select 
              name="modalidad"
              value={formData.modalidad}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {modalidades.map(mod => (
                <option key={mod._id} value={mod._id}>
                  {mod.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Programa:</label>
            <select 
              name="tipo_programa"
              value={formData.tipo_programa}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposPrograma.map(tp => (
                <option key={tp._id} value={tp._id}>
                  {tp.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Oferta:</label>
            <select 
              name="tipo_oferta"
              value={formData.tipo_oferta}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposOferta.map(to => (
                <option key={to._id} value={to._id}>
                  {to.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* CUPOS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Cupos</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Cupo Máximo:</label>
            <input 
              type="number"
              name="cupo_maximo"
              value={formData.cupo_maximo}
              onChange={handleChange}
              style={styles.input}
              placeholder="30"
              min="1"
              required
            />
          </div>
        </div>

        {/* DURACIÓN - Solo para Campesena */}
        {modo === 'campesena' && (
          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Duración</h3>
            <div style={styles.formGroup}>
              <label style={styles.label}>Duración (meses):</label>
              <input 
                type="number"
                name="duracion_meses"
                value={campesenaData.duracion_meses}
                onChange={handleCampesenaChange}
                style={styles.input}
                placeholder="5"
                min="1"
                max="5"
                required
              />
              <small style={styles.hint}>Para Campesena, máximo 5 meses</small>
            </div>
          </div>
        )}

        {/* AMBIENTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Modelo de Ambiente</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Ambiente:</label>
            <input 
              type="text"
              name="ambiente.nombre"
              value={formData.ambiente.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Ej: Aula 101"
              required
            />
          </div>
        </div>

        {/* FECHAS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Fechas</h3>
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Inicio:</label>
              <input 
                type="date"
                name="fechas.inicio"
                value={formData.fechas.inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Fin:</label>
              <input 
                type="date"
                name="fechas.fin"
                value={formData.fechas.fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>
        </div>

        {/* UBICACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Ubicación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Departamento:</label>
            <input 
              type="text"
              name="ubicacion.departamento"
              value={formData.ubicacion.departamento}
              onChange={handleChange}
              style={styles.input}
              placeholder="Cauca"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Municipio:</label>
            <select 
              name="ubicacion.municipio"
              value={formData.ubicacion.municipio}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {municipios.map(mun => (
                <option key={mun._id} value={mun._id}>
                  {mun.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Dirección:</label>
            <input 
              type="text"
              name="ubicacion.direccion"
              value={formData.ubicacion.direccion}
              onChange={handleChange}
              style={styles.input}
              placeholder="Calle 123 #45-67, Barrio Centro"
              required
            />
          </div>
        </div>

        {/* EMPRESA SOLICITANTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Empresa Solicitante</h3>
          
          {!mostrarFormularioEmpresa ? (
            <>
              <div style={styles.formGroup}>
                <label style={styles.label}>Seleccionar Empresa:</label>
                <select 
                  name="empresa_solicitante"
                  value={formData.empresa_solicitante}
                  onChange={handleChange}
                  style={styles.select}
                  required
                >
                  <option value="">Seleccione una empresa...</option>
                  {empresas.map(emp => (
                    <option key={emp._id} value={emp._id}>
                      {emp.nombre} - NIT: {emp.nit}
                    </option>
                  ))}
                </select>
              </div>
              <button 
                type="button"
                onClick={() => setMostrarFormularioEmpresa(true)}
                style={styles.secondaryButton}
              >
                ➕ Crear Nueva Empresa
              </button>
            </>
          ) : (
            <div style={styles.subSection}>
              <h4 style={styles.subSectionTitle}>Nueva Empresa</h4>
              <div style={styles.formGroup}>
                <label style={styles.label}>Nombre de la Empresa:</label>
                <input
                  type="text"
                  name="nombre"
                  value={nuevaEmpresa.nombre}
                  onChange={handleNuevaEmpresaChange}
                  style={styles.input}
                  placeholder="Nombre de la empresa"
                />
              </div>
              {/* ... resto del formulario de nueva empresa (igual que antes) ... */}
              <div style={styles.buttonGroup}>
                <button 
                  type="button"
                  onClick={crearNuevaEmpresa}
                  style={styles.successButton}
                  disabled={loading}
                >
                  {loading ? 'Guardando...' : 'Guardar Empresa'}
                </button>
                <button 
                  type="button"
                  onClick={() => setMostrarFormularioEmpresa(false)}
                  style={styles.cancelButton}
                >
                  Cancelar
                </button>
              </div>
            </div>
          )}
        </div>

        {/* SUBSECTOR ECONÓMICO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Subsector Económico</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre:</label>
            <input 
              type="text"
              name="subsector_economico.nombre"
              value={formData.subsector_economico.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Ej: Tecnologías de la Información"
              required
            />
          </div>
        </div>

        {/* PROGRAMA ESPECIAL */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa Especial</h3>
          <div style={styles.formGroup}>
            <select 
              name="programa_especial"
              value={formData.programa_especial}
              onChange={handleChange}
              style={styles.select}
            >
              <option value="">Ninguno</option>
              {programasEspeciales.map(pe => (
                <option key={pe._id} value={pe._id}>
                  {pe.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* CONVENIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Convenio</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Convenio:</label>
            <input 
              type="text"
              name="convenio.nombre"
              value={formData.convenio.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Nombre del convenio"
              required
            />
          </div>
        </div>

        {/* HORARIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Horario</h3>
          
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Hora Inicio:</label>
              <input 
                type="time"
                name="horario.hora_inicio"
                value={formData.horario.hora_inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Hora Fin:</label>
              <input 
                type="time"
                name="horario.hora_fin"
                value={formData.horario.hora_fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Días:</label>
            <div style={styles.checkboxGroup}>
              {diasSemana.map(dia => (
                <label key={dia} style={styles.checkboxLabel}>
                  <input 
                    type="checkbox"
                    name="horario.dias"
                    value={dia}
                    checked={formData.horario.dias.includes(dia)}
                    onChange={handleChange}
                  /> {dia}
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* INSTRUCTORES ADICIONALES - SOLO PARA CAMPESENA */}
        {modo === 'campesena' && (
          <div style={styles.section}>
            <h3 style={styles.sectionTitle}>Instructores Adicionales</h3>
            
            {/* Instructor 1 */}
            {instructoresVisibles.primerInstructor && (
              <div style={styles.instructorBox}>
                <h4 style={styles.instructorTitle}>Instructor {instructoresVisibles.primerInstructor}</h4>
                
                <div style={styles.formGroup}>
                  <label style={styles.label}>Nombre Completo:</label>
                  <input
                    type="text"
                    value={campesenaData.instructores[0].nombre}
                    onChange={(e) => handleInstructorChange(e, 0)}
                    name="nombre"
                    style={styles.input}
                    placeholder="Nombre completo"
                    required
                  />
                </div>

                <div style={styles.row}>
                  <div style={styles.half}>
                    <label style={styles.label}>Correo:</label>
                    <input
                      type="email"
                      value={campesenaData.instructores[0].correo}
                      onChange={(e) => handleInstructorChange(e, 0)}
                      name="correo"
                      style={styles.input}
                      placeholder="correo@ejemplo.com"
                      required
                    />
                  </div>
                  <div style={styles.half}>
                    <label style={styles.label}>Celular:</label>
                    <input
                      type="tel"
                      value={campesenaData.instructores[0].celular}
                      onChange={(e) => handleInstructorChange(e, 0)}
                      name="celular"
                      style={styles.input}
                      placeholder="3001234567"
                      required
                    />
                  </div>
                </div>

                <h5 style={styles.fechasTitle}>Fechas de Formación (Meses 1-5)</h5>
                <div style={styles.fechasGrid}>
                  {[1, 2, 3, 4, 5].map((mes) => (
                    <div key={mes} style={styles.fechaBox}>
                      <label style={styles.label}>Mes {mes}:</label>
                      <input
                        type="date"
                        value={campesenaData.instructores[0].fechas[mes-1]}
                        onChange={(e) => handleInstructorChange(e, 0)}
                        name={`fechas[${mes-1}]`}
                        style={styles.input}
                        required
                      />
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Instructor 2 */}
            {instructoresVisibles.segundoInstructor && (
              <div style={styles.instructorBox}>
                <h4 style={styles.instructorTitle}>Instructor {instructoresVisibles.segundoInstructor}</h4>
                
                <div style={styles.formGroup}>
                  <label style={styles.label}>Nombre Completo:</label>
                  <input
                    type="text"
                    value={campesenaData.instructores[1].nombre}
                    onChange={(e) => handleInstructorChange(e, 1)}
                    name="nombre"
                    style={styles.input}
                    placeholder="Nombre completo"
                    required
                  />
                </div>

                <div style={styles.row}>
                  <div style={styles.half}>
                    <label style={styles.label}>Correo:</label>
                    <input
                      type="email"
                      value={campesenaData.instructores[1].correo}
                      onChange={(e) => handleInstructorChange(e, 1)}
                      name="correo"
                      style={styles.input}
                      placeholder="correo@ejemplo.com"
                      required
                    />
                  </div>
                  <div style={styles.half}>
                    <label style={styles.label}>Celular:</label>
                    <input
                      type="tel"
                      value={campesenaData.instructores[1].celular}
                      onChange={(e) => handleInstructorChange(e, 1)}
                      name="celular"
                      style={styles.input}
                      placeholder="3001234567"
                      required
                    />
                  </div>
                </div>

                <h5 style={styles.fechasTitle}>Fechas de Formación (Meses 1-5)</h5>
                <div style={styles.fechasGrid}>
                  {[1, 2, 3, 4, 5].map((mes) => (
                    <div key={mes} style={styles.fechaBox}>
                      <label style={styles.label}>Mes {mes}:</label>
                      <input
                        type="date"
                        value={campesenaData.instructores[1].fechas[mes-1]}
                        onChange={(e) => handleInstructorChange(e, 1)}
                        name={`fechas[${mes-1}]`}
                        style={styles.input}
                        required
                      />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ARCHIVOS PDF */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Documentos Adjuntos</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Firma Digital (PDF):</label>
            <div style={styles.fileInputGroup}>
              <input
                type="file"
                id="firma_digital_pdf"
                name="firma_digital_pdf"
                onChange={handleFileChange}
                style={styles.fileInput}
                accept=".pdf"
              />
              {formData.firma_digital_pdf && (
                <div style={styles.fileInfo}>
                  <span style={styles.fileName}>{formData.firma_digital_pdf.name}</span>
                  <button
                    type="button"
                    onClick={() => {
                      document.getElementById('firma_digital_pdf').value = '';
                      setFormData({...formData, firma_digital_pdf: null});
                    }}
                    style={styles.removeFileButton}
                  >
                    ✕
                  </button>
                </div>
              )}
            </div>
            <small style={styles.fileHint}>Archivo PDF con la firma digital escaneada</small>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Carta (PDF):</label>
            <div style={styles.fileInputGroup}>
              <input
                type="file"
                id="carta_pdf"
                name="carta_pdf"
                onChange={handleFileChange}
                style={styles.fileInput}
                accept=".pdf"
              />
              {formData.carta_pdf && (
                <div style={styles.fileInfo}>
                  <span style={styles.fileName}>{formData.carta_pdf.name}</span>
                  <button
                    type="button"
                    onClick={() => {
                      document.getElementById('carta_pdf').value = '';
                      setFormData({...formData, carta_pdf: null});
                    }}
                    style={styles.removeFileButton}
                  >
                    ✕
                  </button>
                </div>
              )}
            </div>
            <small style={styles.fileHint}>Documento PDF de la carta solicitante</small>
          </div>
        </div>

        <button 
          type="submit" 
          style={loading ? {...styles.submitButton, ...styles.buttonDisabled} : styles.submitButton}
          disabled={loading}
        >
          {loading ? 'Guardando...' : 'Guardar Oferta'}
        </button>
      </form>
    </div>
  );
};

// ===== ESTILOS (incluir todos los estilos anteriores más estos nuevos) =====
const styles = {
  container: {
    maxWidth: '800px',
    margin: '0 auto',
    padding: '20px',
    fontFamily: 'Arial, sans-serif'
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '30px'
  },
  title: {
    color: '#2c3e50',
    borderBottom: '3px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '0',
    fontSize: '28px'
  },
  cambiarModoButton: {
    backgroundColor: '#95a5a6',
    color: 'white',
    padding: '8px 16px',
    border: 'none',
    borderRadius: '4px',
    fontSize: '14px',
    fontWeight: 'bold',
    cursor: 'pointer',
    ':hover': {
      backgroundColor: '#7f8c8d'
