    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRadius: '8px',
    marginBottom: '25px',
    border: '1px solid #e0e0e0'
  },
  subSection: {
    backgroundColor: '#ffffff',
    padding: '15px',
    borderRadius: '6px',
    marginTop: '10px',
    border: '1px solid #3498db'
  },
  sectionTitle: {
    color: '#2c3e50',
    marginTop: 0,
    marginBottom: '20px',
    fontSize: '18px',
    borderBottom: '1px solid #3498db',
    paddingBottom: '5px'
  },
  subSectionTitle: {
    color: '#3498db',
    marginTop: 0,
    marginBottom: '15px',
    fontSize: '16px'
  },
  instructorBox: {
    backgroundColor: '#f0f7ff',
    padding: '15px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '1px solid #3498db'
  },
  instructorTitle: {
