    marginBottom: '15px',
    fontSize: '16px'
  },
  fechasTitle: {
    color: '#2c3e50',
    margin: '15px 0 10px 0',
    fontSize: '14px'
  },
  fechasGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(120px, 1fr))',
